import{_ as a,o as t,c as n,j as r,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"干草镰刀","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/干草镰刀.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/干草镰刀.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/干草镰刀.md"};function b(l,e,_,p,i,c){return t(),n("div",null,[...e[0]||(e[0]=[r("h1",{id:"干草镰刀",tabindex:"-1"},[s("干草镰刀 "),r("a",{class:"header-anchor",href:"#干草镰刀","aria-label":'Permalink to "干草镰刀"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌034")])])],-1),o('<h1 id="干草镰刀-1" tabindex="-1">干草镰刀 <a class="header-anchor" href="#干草镰刀-1" aria-label="Permalink to &quot;干草镰刀&quot;">​</a></h1><p>干草镰刀<br> d+500<br> 特异本质<br> 类型：武器/镰刀<br> 原典：星露谷、我的世界、泰拉瑞亚<br> 武器伤害5L 轻灵 破甲1 挥砍 体积2<br> 割下鲜草，会获得干草。<br> 干草作用可多了，当垫脚方块，当储备干粮，当动物饲料——<br> 当你对着鲜草进行收割动作时，它们将变为干草，并储存在你的一个储物空间谷仓中，这个谷仓只有3立方米左右的空间，每攒够1立方米的干草，干草将自动绑成一个干草块，可以堆叠起来当墙壁，隔断，或者当做垫脚草。<br> 这个谷仓无法储存其他物品，取出干草或干草块时需要一个移动动作。<br> 不过，不是所有干草都能够当做食物；<br> 起码普通人没法消化干草……<br> 每场影片中，你每天第一次收割作物时，收割过后你将额外获得1份小麦，每场影片至多可获得3份小麦，小麦不占用谷仓的位置，而是在你不知道在哪里的物品栏里，小麦可在影片结束后带出影片。<br> 小麦无法直接食用，但可以通过造物规则将其制作为小麦面包，三份小麦可以制作一份小麦面包。</p><p>【小麦面包】<br> 特异本质<br> 类型：消耗品<br> 价格：三份小麦（2xp）<br> 饱食：以一个迅捷动作使用，食用后将获得饱食度提升，并且在该场景中将自动稳定伤势，不会使其恶化<br> 满饱食：当你食用小麦面包后，若生命值不为满值，你的生命值将缓慢恢复，每轮回复1点生命值，上限12点，这是一个来源于【快疗1】的生命恢复效果，因为饱腹感充足导致吃不下，同一时间只能食用一个。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',5)])])}const m=a(d,[["render",b]]);export{f as __pageData,m as default};
